// /pages/DashboardLayout.jsx

import {Link, Outlet} from "react-router-dom";

const DashboardLayout = () => {
 return (
  &lt;div style={{display: 'flex'}}>
   {/* Sidebar (bleibt immer gleich) */}
   &lt;aside style={{width: '200px', background: '#eee', padding: '10px'}}>
    &lt;h3>Dashboard&lt;/h3>
    &lt;nav>
     &lt;Link to="/dashboard">Übersicht&lt;/Link>&lt;br/>
     &lt;Link to="/dashboard/stats">Statistiken&lt;/Link>&lt;br/>
     &lt;Link to="/dashboard/settings">Einstellungen&lt;/Link>
    &lt;/nav>
   &lt;/aside>

   {/* Hauptinhalt (wechselt je nach Unterseite) */}
   &lt;main style={{padding: '10px'}}>
    &lt;Outlet/> {/* Hier kommen die Unterseiten rein! */}
   &lt;/main>
  &lt;/div>
 )
}

export default DashboardLayout;

// App.jsx
import {BrowserRouter, Routes, Route, Link} from 'react-router-dom';

import Home from './pages/Home.jsx'

import DashboardLayout from './pages/DashboardLayout';
import DashboardOverview from './pages/dashboard/Overview.jsx';
import DashboardStats from './pages/dashboard/Stats.jsx';
import DashboardSettings from './pages/dashboard/Settings.jsx';

const App = () => {
 return (
  &lt;BrowserRouter>

   &lt;nav>
    &lt;Link to="/">Home&lt;/Link>
    &lt;Link to="/dashboard">Dashboard&lt;/Link>
   &lt;/nav>

   &lt;Routes>
    &lt;Route path="/" element={&lt;Home/>}/>

    {/* Eltern-Route: Zeigt DashboardLayout + Unterseite */}
    &lt;Route path="/dashboard" element={&lt;DashboardLayout/>}>

     {/* Unterseiten (werden in &lt;Outlet /> gerendert) */}
     &lt;Route index element={&lt;DashboardOverview/>}/> {/* /dashboard       */}
     &lt;Route path="stats" element={&lt;DashboardStats/>}/> {/* /dashboard/stats */}
     &lt;Route path="settings" element={&lt;DashboardSettings/>}/> {/* /dashboard/settings */}

    &lt;/Route>
   &lt;/Routes>
  &lt;/BrowserRouter>
 );
}

export default App;
